"""
file_mw — 文件中间件，替代 relay_tasks 和 sim_config 的 SQLite 操作
inbox/outbox 仍保留在 relay_mw.py（SQLite）
"""
import json
import os
import time
import threading
import datetime

BASE = os.path.expanduser('~/relay_mw')
TASKS_DIR = os.path.join(BASE, 'tasks')
SIM_CFG = os.path.join(BASE, 'sim_config.json')
_lock = threading.Lock()


def _ensure_dir():
    os.makedirs(TASKS_DIR, exist_ok=True)


def _task_path(relay_id):
    return os.path.join(TASKS_DIR, relay_id.replace('/', '_') + '.json')


def _now():
    return time.time()


# ─── sim_config ────────────────────────────────────────

_DEFAULT_SIM = {
    'enabled': True,
    'person_found': True,
    'wait_seconds': 10,
    'max_retries': 3,
}


def read_sim_config():
    try:
        with open(SIM_CFG, 'r') as f:
            return json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        return dict(_DEFAULT_SIM)


def write_sim_config(cfg):
    with _lock:
        _ensure_dir()
        tmp = SIM_CFG + '.tmp'
        with open(tmp, 'w') as f:
            json.dump(cfg, f, ensure_ascii=False)
        os.replace(tmp, SIM_CFG)


# ─── relay_tasks (文件版) ─────────────────────────────

def insert_task(relay_id, payload, content, scheduled_at=None):
    """写入一条传话任务文件"""
    if scheduled_at is None:
        scheduled_at = _now()
    task = {
        'relay_id': relay_id,
        'payload': payload,
        'content': content,
        'status': 'pending',
        'scheduled_at': scheduled_at,
        'delay_count': 0,
        'next_check': None,
        'created_at': _now(),
        'executed_at': None,
        'reported': False,
    }
    with _lock:
        _ensure_dir()
        path = _task_path(relay_id)
        tmp = path + '.tmp'
        with open(tmp, 'w') as f:
            json.dump(task, f, ensure_ascii=False)
        os.replace(tmp, path)


def pop_due_tasks():
    """遍历任务目录，查出到期待处理的任务"""
    now = _now()
    due = []
    try:
        for fname in os.listdir(TASKS_DIR):
            if not fname.endswith('.json'):
                continue
            path = os.path.join(TASKS_DIR, fname)
            try:
                with open(path, 'r') as f:
                    task = json.load(f)
            except (json.JSONDecodeError, OSError):
                continue

            status = task.get('status', 'pending')
            if status not in ('pending', 'executing'):
                continue

            sched = task.get('scheduled_at')
            if sched is None:
                continue
            if sched > now:
                continue

            next_c = task.get('next_check')
            if next_c is not None and next_c > now:
                continue

            due.append(task)
    except FileNotFoundError:
        pass

    # 按 scheduled_at 排序
    due.sort(key=lambda t: t.get('scheduled_at', 0))
    return due[:10]


def update_task_status(relay_id, status, delay_count=None, next_check=None, executed_at=None):
    """更新任务状态"""
    with _lock:
        path = _task_path(relay_id)
        try:
            with open(path, 'r') as f:
                task = json.load(f)
        except (FileNotFoundError, json.JSONDecodeError):
            return

        task['status'] = status
        if delay_count is not None:
            task['delay_count'] = delay_count
        if next_check is not None:
            task['next_check'] = next_check
        if executed_at is not None:
            task['executed_at'] = executed_at
        if status in ('completed', 'failed'):
            task['reported'] = False

        tmp = path + '.tmp'
        with open(tmp, 'w') as f:
            json.dump(task, f, ensure_ascii=False)
        os.replace(tmp, path)


def pop_unreported():
    """取一条已执行但未上报的任务"""
    try:
        for fname in sorted(os.listdir(TASKS_DIR)):
            if not fname.endswith('.json'):
                continue
            path = os.path.join(TASKS_DIR, fname)
            try:
                with open(path, 'r') as f:
                    task = json.load(f)
            except (json.JSONDecodeError, OSError):
                continue

            status = task.get('status', '')
            reported = task.get('reported', False)
            if status in ('completed', 'failed') and not reported:
                return task
    except FileNotFoundError:
        pass
    return None


def mark_reported(relay_id):
    """标记已上报，然后删除文件"""
    path = _task_path(relay_id)
    try:
        os.remove(path)
    except FileNotFoundError:
        pass


def delete_task(relay_id):
    path = _task_path(relay_id)
    try:
        os.remove(path)
    except FileNotFoundError:
        pass
